<style>
.hb-local-desc {
  margin: 12px 16px 0;
  padding: 12px;
  border: 1px solid #ececec;
  border-radius: 10px;
  background: #fff;
}
.hb-local-desc h3 {
  margin: 0 0 8px;
  font-size: 15px;
  color: #222;
}
.hb-local-desc p {
  margin: 0;
  color: #555;
  font-size: 13px;
  line-height: 1.45;
}
.hb-local-action-bar {
  position: fixed;
  left: 0;
  right: 0;
  bottom: 0;
  z-index: 99999;
  background: #fff;
  border-top: 1px solid #ececec;
  padding: 8px 10px calc(8px + env(safe-area-inset-bottom));
  display: flex;
  gap: 8px;
}
.hb-local-action-bar .hb-local-fav {
  width: 42px;
  height: 42px;
  border: 1px solid #e2e2e2;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #666;
  font-size: 18px;
  flex: 0 0 42px;
}
.hb-local-action-bar .hb-local-btn {
  flex: 1;
  height: 42px;
  border: 0;
  border-radius: 10px;
  background: #ff6000;
  color: #fff;
  text-decoration: none;
  font-size: 14px;
  font-weight: 600;
  display: flex;
  align-items: center;
  justify-content: center;
}
body {
  padding-bottom: 64px !important;
}
</style>
<script>
(function () {
  var cartUrl = <?php echo json_encode($hbCartUrl, JSON_UNESCAPED_UNICODE); ?>;
  var productTitle = <?php echo json_encode($hbProductTitle, JSON_UNESCAPED_UNICODE); ?>;
  var descriptionText = <?php echo json_encode($hbDescription, JSON_UNESCAPED_UNICODE); ?>;

  function isBlockedExternal(url) {
    if (!url) return false;
    if (/^(#|javascript:|mailto:|tel:)/i.test(url)) return false;
    try {
      var parsed = new URL(url, window.location.href);
      if (parsed.hostname === window.location.hostname) return false;
      if (/hepsiburada\.com$/i.test(parsed.hostname)) return true;
      return parsed.hostname !== window.location.hostname;
    } catch (e) {
      return false;
    }
  }

  function patchLinks() {
    var links = document.querySelectorAll('a[href]');
    links.forEach(function (a) {
      var href = a.getAttribute('href') || '';
      if (isBlockedExternal(href)) {
        a.setAttribute('href', 'javascript:void(0)');
        a.setAttribute('data-hb-blocked-link', '1');
      }
    });
  }

  function injectDescription() {
    if (document.getElementById('hb-local-desc')) return;
    var mount = document.querySelector('[data-test-id="buybox-area"]') || document.querySelector('main');
    if (!mount) return;
    var box = document.createElement('section');
    box.id = 'hb-local-desc';
    box.className = 'hb-local-desc';
    box.innerHTML =
      '<h3>Ürün Açıklaması</h3>' +
      '<p><strong>' + (productTitle || 'Ürün') + '</strong><br>' + (descriptionText || '') + '</p>';
    mount.appendChild(box);
  }

  function injectActionBar() {
    if (document.getElementById('hb-local-action-bar')) return;
    var bar = document.createElement('div');
    bar.id = 'hb-local-action-bar';
    bar.className = 'hb-local-action-bar';
    bar.innerHTML =
      '<div class="hb-local-fav" aria-hidden="true">♡</div>' +
      '<a class="hb-local-btn" href="' + cartUrl + '">Sepete Ekle</a>';
    document.body.appendChild(bar);
  }

  document.addEventListener('click', function (e) {
    var link = e.target && e.target.closest ? e.target.closest('a[data-hb-blocked-link="1"]') : null;
    if (!link) return;
    e.preventDefault();
    e.stopPropagation();
  }, true);

  var nativeOpen = window.open;
  window.open = function (url) {
    if (isBlockedExternal(url)) return null;
    return nativeOpen.apply(window, arguments);
  };

  patchLinks();
  injectDescription();
  injectActionBar();
})();
</script>
